#include <bits/stdc++.h>
using namespace std;

const int N=6e6+10;

int T,m=6e6;
int pr[N],cnt,mu[N],phi[N],sm[N];
long long n,f[N+5000],sp[N];
bool np[N],b[N+5000];

void init(){
    np[0]=np[1]=1;
    mu[1]=1,phi[1]=1;
    for(int i=2;i<=m;i++){
        if(!np[i]) pr[++cnt]=i,mu[i]=-1,phi[i]=i-1;
        for(int j=1;1ll*pr[j]*i<=m;j++){
            np[pr[j]*i]=1;
            phi[pr[j]*i]=phi[i]*pr[j];
            if(i%pr[j]==0) break;
            mu[pr[j]*i]=-mu[i];
            phi[pr[j]*i]=phi[pr[j]*i]/pr[j]*(pr[j]-1);
        }
    }
    for(int i=1;i<=m;i++)
        sm[i]=sm[i-1]+mu[i],sp[i]=sp[i-1]+phi[i];
}

long long getmu(long long n,long long &x){
    int p=(n>m?x/n+m:n);
    if(b[p]) return f[p];
    b[p]=1;
    long long res=1;
    for(long long l=2,r;l<=n;l=r+1){
        r=n/(n/l);
        res-=(r-l+1)*getmu(n/l,x);
    }
    return f[p]=res;
}

long long getphi(long long n,long long &x){
    int p=(n>m?x/n+m:n);
    if(b[p]) return f[p];
    b[p]=1;
    long long res=1ll*n*(n+1)/2;
    for(long long l=2,r;l<=n;l=r+1){
        r=n/(n/l);
        res-=(r-l+1)*getphi(n/l,x);
    }
    return f[p]=res;
}

int main(){
    init();
    scanf("%d",&T);
    while(T--){
        scanf("%lld",&n);
        memset(b,0,sizeof(b));
        for(int i=1;i<=m;i++)
            b[i]=1,f[i]=sp[i];
        printf("%lld ",getphi(n,n));
        memset(b,0,sizeof(b));
        for(int i=1;i<=m;i++)
            b[i]=1,f[i]=sm[i];
        printf("%lld\n",getmu(n,n));
    }
    return 0;
}
